examples.code:
// break:
for(int i=0;i<10;i++){
    if(i==5) break;
    System.out.print(i+" ");
}
// 0 1 2 3 4

// continue — skip odds:
for(int i=0;i<8;i++){
    if(i%2!=0) continue;
    System.out.print(i+" ");
}
// 0 2 4 6

for(int i=1;i<=3;i++){
    for(int j=1;j<=3;j++){
        System.out.print(i*j+" ");
    }
    System.out.println();
}
// 1 2 3
// 2 4 6
// 3 6 9

